async function createButton(config) {
  try {
    const btn = await window.zclient.invoke("ui.create", config);
    if (btn.error) throw btn.error;
    return { success: true, data: window.zclient.instance(btn.uid) };
  } catch (e) {
    createLog("createButton", "Failed to create Button", "", "error");
    return { success: false, data: e };
  }
}

async function createModal(config) {
  try {
    const modal = await window.zclient.invoke("ui.create", config);
    return { success: true, data: window.zclient.instance(modal.uid) };
  } catch (e) {
    createLog("createModal", "Failed to create Modal", "", "error");
    return { success: false, data: e };
  }
}

async function createToast(config) {
  try {
    const toast = await window.zclient.invoke("ui.create", config);
    return { success: true, data: window.zclient.instance(toast.uid) };
  } catch (e) {
    createLog("createToast", "Failed to create Toast", "", "error");
    return { success: false, data: e };
  }
}

async function createDialog(config) {
  try {
    const dialog = await window.zclient.invoke("ui.create", config);
    return { success: true, data: window.zclient.instance(dialog.uid) };
  } catch (e) {
    createLog("createDialog", "Failed to create Dialog", "", "error");
    return { success: false, data: e };
  }
}

async function getUserTeams(userUid) {
  const res = await window.zclient.request({
    url: "/user/" + userUid + "/teams",
    type: "GET",
    cors: false,
    contentType: "application/json",
    externalRequest: false,
  });
  return res?.body?.data ?? [];
}

async function getJobDetails(jobUid) {
  const res = await window.zclient.request({
    url: "/jobs/" + jobUid,
    type: "GET",
    cors: false,
    contentType: "application/json",
    externalRequest: false,
  });
  return res?.body?.data;
}

function createLog(fnName, message, page, level, metadata) {
  page     = page     || "";
  level    = level    || "default";
  metadata = metadata || {};
  const entry = {
    level,
    message: "SDK: fn: " + fnName + (page ? " : page: " + page : "") + " - " + message,
    metadata,
  };
  const fn = level === "info"  ? console.info
           : level === "warn"  ? console.warn
           : level === "error" ? console.error
           : console.log;
  fn(JSON.stringify(entry, null, 2));
}

function genUUID() {
  return (Date.now().toString() + Math.random().toString(36).substring(2, 7)).substring(0, 15);
}

function wait(ms) {
  return new Promise(function(resolve) { setTimeout(resolve, ms); });
}
